127→const callGemini = async (model: string, prompt: string, apiKey: string): Promise<GeminiAnalysis> => {
128→  const controller = new AbortController();
129→  const timeoutId = setTimeout(() => controller.abort(), 30_000);
130→  const response = await fetch(`https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${apiKey}`, {
131→    method: 'POST',
132→    signal: controller.signal,
133→    headers: {
134→      'Content-Type': 'application/json',
135→    },
136→    body: JSON.stringify({
137→      contents: [{ parts: [{ text: prompt }] }],
138→      generationConfig: {
139→        responseMimeType: 'application/json',
140→        temperature: 0.3,
141→      },
142→    }),
143→  });
144→  clearTimeout(timeoutId);
145→  if (!response.ok) {
146→    throw new Error(`Gemini error: ${response.status}`);
147→  }
148→  const payload = (await response.json()) as {
149→    candidates?: Array<{ content?: { parts?: Array<{ text?: string }> } }>;
150→  };
151→  const text = payload.candidates?.[0]?.content?.parts?.[0]?.text ?? '';
152→  if (!text) {
153→    throw new Error('Gemini reponse vide');
154→  }
155→  return parseGeminiText(text);
156→};
